//! Canonical AXT fixtures shared across SDKs and guard scripts.
//!
//! These fixtures are generated by `cargo run -p iroha_data_model --features test-fixtures --bin axt_fixtures`
//! and exercised by both Rust and SDK tests to catch schema or binding drift.

use hex::decode;
use iroha_crypto::HashOf;
use iroha_schema::IntoSchema;
use norito::json;

use crate::{
    DeriveJsonDeserialize, DeriveJsonSerialize,
    nexus::{AxtDescriptor, AxtHandleFragment, AxtProofFragment, AxtTouchFragment},
};

const DESCRIPTOR_FIXTURE: &[u8] = include_bytes!(concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/tests/fixtures/axt_descriptor_multi_ds.json"
));
const ENVELOPE_FIXTURE: &[u8] = include_bytes!(concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/tests/fixtures/axt_envelope_multi_ds.json"
));
const POSEIDON_FIXTURE: &[u8] = include_bytes!(concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/tests/fixtures/axt_poseidon_constants.json"
));

/// Descriptor/touch fixture with Norito bytes and binding.
#[derive(Debug, Clone, DeriveJsonDeserialize, DeriveJsonSerialize, PartialEq, Eq, IntoSchema)]
pub struct DescriptorFixture {
    /// Canonical descriptor.
    pub descriptor: AxtDescriptor,
    /// Descriptor encoded using the Norito codec (hex).
    pub descriptor_hex: String,
    /// Example touch manifests keyed by dataspace.
    pub touch_manifest: Vec<AxtTouchFragment>,
    /// Binding derived from the descriptor (hex).
    pub binding_hex: String,
}

impl DescriptorFixture {
    /// Decode the Norito descriptor bytes embedded in the fixture.
    #[must_use]
    pub fn descriptor_bytes(&self) -> Vec<u8> {
        decode(&self.descriptor_hex).expect("descriptor hex decodes")
    }

    /// Retrieve the binding bytes encoded as hex.
    #[must_use]
    pub fn binding_bytes(&self) -> Vec<u8> {
        decode(&self.binding_hex).expect("binding hex decodes")
    }
}

/// Happy-path and reject fixtures for handles/proofs.
#[derive(Debug, Clone, DeriveJsonDeserialize, DeriveJsonSerialize, PartialEq, Eq, IntoSchema)]
pub struct HandleFixtures {
    /// Valid handle fragments.
    pub happy: Vec<AxtHandleFragment>,
    /// Deliberately invalid handle fragments.
    pub rejects: Vec<AxtHandleFragment>,
}

/// Aggregated AXT envelope fixture.
#[derive(Debug, Clone, DeriveJsonDeserialize, DeriveJsonSerialize, PartialEq, Eq, IntoSchema)]
pub struct EnvelopeFixture {
    /// Descriptor bytes (hex) used to derive bindings.
    pub descriptor_hex: String,
    /// Binding derived from the descriptor (hex).
    pub binding_hex: String,
    /// Proof fragments keyed by dataspace.
    pub proofs: Vec<AxtProofFragment>,
    /// Handle fixtures.
    pub handles: HandleFixtures,
}

impl EnvelopeFixture {
    /// Return the canonical binding bytes for the descriptor.
    #[must_use]
    pub fn binding_bytes(&self) -> Vec<u8> {
        decode(&self.binding_hex).expect("binding hex decodes")
    }
}

/// Exported Poseidon parameter fixture (hex-encoded field elements).
#[derive(Debug, Clone, DeriveJsonDeserialize, DeriveJsonSerialize, PartialEq, Eq, IntoSchema)]
pub struct PoseidonParamsFixture {
    /// Round constants encoded as hex strings per lane.
    pub round_constants: Vec<Vec<String>>,
    /// MDS matrix entries encoded as hex strings.
    pub mds: Vec<Vec<String>>,
}

/// Poseidon parameter fixtures for the supported widths.
#[derive(Debug, Clone, DeriveJsonDeserialize, DeriveJsonSerialize, PartialEq, Eq, IntoSchema)]
pub struct PoseidonConstantsFixture {
    /// Width-3 Poseidon2 parameters.
    pub width3: PoseidonParamsFixture,
    /// Width-6 Poseidon2 parameters.
    pub width6: PoseidonParamsFixture,
}

/// Load the canonical descriptor fixture.
#[must_use]
pub fn descriptor_fixture() -> DescriptorFixture {
    json::from_slice(DESCRIPTOR_FIXTURE).expect("descriptor fixture decodes")
}

/// Load the canonical envelope fixture.
#[must_use]
pub fn envelope_fixture() -> EnvelopeFixture {
    json::from_slice(ENVELOPE_FIXTURE).expect("envelope fixture decodes")
}

/// Load Poseidon parameter fixtures as hex strings.
#[must_use]
pub fn poseidon_constants_fixture() -> PoseidonConstantsFixture {
    json::from_slice(POSEIDON_FIXTURE).expect("poseidon fixture decodes")
}

/// Compute a Blake2 hash of an encoded descriptor for quick integrity checks.
#[must_use]
pub fn descriptor_hash(fixture: &DescriptorFixture) -> HashOf<AxtDescriptor> {
    HashOf::new(&fixture.descriptor)
}
